WorkflowProcessEvent.eventDescription:
function afterProcessCreate(processId){
	log.info("###afterProcessCreate");

	var dat = new Date(); 
	dat.getFullYear();

	hAPI.setCardValue("numcontrato",processId + "-" + dat.getFullYear());


//	hAPI.setCardValue("status","Venda Iniciada");


	solicitacao = getValue("WKNumProces");
	hAPI.setCardValue("requestFluig",solicitacao);

	cpf                 = hAPI.getCardValue("cpf");
	nomecliente         = hAPI.getCardValue("nomecliente");
	codEmpreendimento 	= hAPI.getCardValue("codEmpreendimento");
	lote				= hAPI.getCardValue("lote");
	quadra				= hAPI.getCardValue("quadra");

	var empreendimento = hAPI.getCardValue("empreendimento");
	
	var descritor = "Empreendimento: " + empreendimento +
					"\n" +
					"Lote: " + lote +
					"\n" +
					"Quadra: " + quadra +
					"\n" +
					"Comprador: " + cpf + " | " + nomecliente;
	hAPI.setCardValue("descritor", descritor);
	//hAPI.setCardValue("descritor", codEmpreendimento + "-" + lote + "-" + quadra + "|" + cpf);

	if (empreendimento == "VIVERDE RIO DAS OSTRAS - 1ª FASE") {
		hAPI.setCardValue("tipoEmpreendimento", "v1");
	} else if (empreendimento == "VIVERDE RIO DAS OSTRAS - 2ª FASE") {
		hAPI.setCardValue("tipoEmpreendimento", "v2");
	} else if (empreendimento == "VIVERDE RIO DAS OSTRAS - 3ª FASE") {
		hAPI.setCardValue("tipoEmpreendimento", "v2");
	}
}

function montaXmlRMCriarClienteFornecedor(cardData,codigoCFO){

		var c1, constraints = null;
		c1 = DatasetFactory.createConstraint("cpfCnpj", cardData.get('cpf'), cardData.get('cpf'), ConstraintType.MUST);

		constraints = new Array(c1);

		// Faz a chamada para obter o dataset
		var dataset = DatasetFactory.getDataset("dsClientes", null, constraints, null);

		log.info("PASSEI DO DATASET");
		log.info("LINHAS: " + dataset.rowsCount);
		log.info("CPFCNPJ DATASET: "+dataset.getValue(0,"cpfCnpj"));
		log.info("###montaXmlRMClienteFornecedor");
		var date = new Date();
		var hoje = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss").format(date);

		var motivo = "";

		var CODCOLIGADA = "0";
		var CODCFO = codigoCFO;
		var CFOIMOB = "0";
		var NOMEFANTASIA = dataset.getValue(0,"nomeCliente");
		var NOME = dataset.getValue(0,"nomeCliente");
		var CGCCFO = dataset.getValue(0,"cpfCnpj");
		var INSCRESTADUAL = "0000";//dataset.getValue(0,"inscest");
		var INSCRMUNICIPAL = "1" + dataset.getValue(0,"inscmun");
		var PAGREC = "3";
		
		var RUA = ""; 
		if( dataset.getValue(0,"logradouro") == "" || dataset.getValue(0,"logradouro") == undefined || dataset.getValue(0,"logradouro") == null ){
			RUA = dataset.getValue(0,"logradouropj");
		} else {
			RUA = dataset.getValue(0,"logradouro");
		}
		var NUMERO = "";
		if( dataset.getValue(0,"numero") == "" || dataset.getValue(0,"numero") == undefined || dataset.getValue(0,"numero") == null ){
			NUMERO = dataset.getValue(0,"numeropj");
		} else {
			NUMERO = dataset.getValue(0,"numero");
		}
		
		var COMPLEMENTO = "";
		if( dataset.getValue(0,"complemento") == "" || dataset.getValue(0,"complemento") == undefined || dataset.getValue(0,"complemento") == null ){
			COMPLEMENTO = dataset.getValue(0,"complementopj");
		} else {
			COMPLEMENTO = dataset.getValue(0,"complemento");
		}
		
		var BAIRRO = "";
		if( dataset.getValue(0,"bairro") == "" || dataset.getValue(0,"bairro") == undefined || dataset.getValue(0,"bairro") == null ){
			BAIRRO = dataset.getValue(0,"bairropj");
		} else {
			BAIRRO = dataset.getValue(0,"bairro");
		}
		
		var CIDADE = "";
		if( dataset.getValue(0,"cidade") == "" || dataset.getValue(0,"cidade") == undefined || dataset.getValue(0,"cidade") == null ){
			CIDADE = dataset.getValue(0,"cidadepj");
		} else {
			CIDADE = dataset.getValue(0,"cidade");
		}
			
		var CODETD = "";
		if( dataset.getValue(0,"estado") == "" || dataset.getValue(0,"estado") == undefined || dataset.getValue(0,"estado") == null ){
			CODETD = dataset.getValue(0,"estadopj");
		} else {
			CODETD = dataset.getValue(0,"estado");
		}
		var CODMUNICIPIO = ""; //"04557";
		
		var cc1 = DatasetFactory.createConstraint("UF", CODETD, CODETD, ConstraintType.MUST);
		var cc2 = DatasetFactory.createConstraint("NOME", CIDADE, CIDADE, ConstraintType.MUST);
		
		var constraintCidade = new Array(cc1, cc2);
		var dsObterCidade = DatasetFactory.getDataset("dsObterCidade", null, constraintCidade, null);
		if (dsObterCidade.rowsCount <= 0){
			throw "Cidade ["+CIDADE+"] não encontrada na UF ["+CODETD+"].";
		} else {
