		}
		
		
		var CEP = "";
			if( dataset.getValue(0,"cep") == "" || dataset.getValue(0,"cep") == undefined || dataset.getValue(0,"cep") == null ){
				CEP = dataset.getValue(0,"ceppj");
			} else {
				CEP = dataset.getValue(0,"cep");
			}
		var TELEFONE = "";
			if( dataset.getValue(0,"telres").replace("(", "").replace(")", "").replace(" ", "") == "" || dataset.getValue(0,"telres").replace("(", "").replace(")", "").replace(" ", "") == undefined || dataset.getValue(0,"telres").replace("(", "").replace(")", "").replace(" ", "") == null ){
				TELEFONE = dataset.getValue(0,"telpj").replace("(", "").replace(")", "").replace(" ", "");
			} else {
				TELEFONE = dataset.getValue(0,"telres").replace("(", "").replace(")", "").replace(" ", "");
			}
		var TELEX = ""
			if( dataset.getValue(0,"celular").replace("(", "").replace(")", "").replace(" ", "") == "" || dataset.getValue(0,"celular").replace("(", "").replace(")", "").replace(" ", "") == undefined || dataset.getValue(0,"celular").replace("(", "").replace(")", "").replace(" ", "") == null ){
				TELEX = dataset.getValue(0,"telpj").replace("(", "").replace(")", "").replace(" ", "");
			} else {
