		var RUAPGTO = dataset.getValue(0,"endcom");
		var NUMEROPGTO = dataset.getValue(0,"numerocom");
		var COMPLEMENTOPGTO = dataset.getValue(0,"complementocom");
		var BAIRROPGTO = dataset.getValue(0,"bairrocom");
