		var NUMEROENTREGA = dataset.getValue(0,"numerocom");
		var COMPLEMENTOENTREGA = dataset.getValue(0,"complementocom");
		var BAIRROENTREGA = dataset.getValue(0,"bairrocom");
		var CIDADEENTREGA = dataset.getValue(0,"cidadecom");
		var CODETDENTREGA = dataset.getValue(0,"estadocom");
		var CODMUNICIPIOENTREGA = ""//"04557";
		var CEPENTREGA = dataset.getValue(0,"cepcom");
		var TELEFONEENTREGA = "1111";//dataset.getValue(0,"telcom");
		var EMAILENTREGA = dataset.getValue(0,"email");
		var CONTATOENTREGA = dataset.getValue(0,"nomeCliente");

		var CODTCF = "101";
		var LIMITECREDITO = "";
		var ATIVO = "1";
		var CODCOLTCF = "0";
		var PESSOAFISOUJUR = dataset.getValue(0,"fisOuJur");
		var USUARIOALTERACAO = "admin";
		var RECCREATEDBY = "admin";
		var IDCFO = "-1";
		var TIPORUA = "1";
