					"<USUARIOALTERACAO>"+USUARIOALTERACAO+"</USUARIOALTERACAO>"+
					"<RECCREATEDBY>"+RECCREATEDBY+"</RECCREATEDBY>"+
					"<IDCFO>"+IDCFO+"</IDCFO>"+
					"<TIPORUA>"+TIPORUA+"</TIPORUA>"+
