//				"<FDADOSPGTO>"+
//					"<CODCFO>"+cardData.get('codCfo')+"</CODCFO>" +
//					"<DESCRICAO>TESTE</DESCRICAO>"+
//				"</FDADOSPGTO>"+
		      "</FinCFOBR>";

		var XML_TRATADO = XML.split("&").join("&amp;");

		return XML_TRATADO;
}

function beforeTaskSave(colleagueId,nextSequenceId,userList){
	
	tipo     = hAPI.getCardValue("cpf");
	tamanho  = tipo.length();

	if (tamanho == 14){
		tipo = "F"
	} else
	if (tamanho == 18){
		tipo = "J"
	}

	numState = getValue("WKNumState");
	process  = getValue("WKNumProces");
	anexado  = false;
	message  = "";

    if((numState == 5) && hAPI.listAttachments().size() < 5 && tipo == "F") {
        message += "<br/>- É necessario anexar os <b>seguintes Documentos:</b><br/><br/>" +
        	        " - RG;<br>" +
        	        " - CPF;<br>" +
        	        " - Comprovante de Residência;<br>" +
        	        " - Imposto de Renda;<br>" +
        	        " - Carta Proposta;<br><br>" +
        	        " São necessários <b><u>5</u></b> documentos, você anexou <b><u>"+ hAPI.listAttachments().size() +"</u></b><br>";
    }

    if((numState == 5) && hAPI.listAttachments().size() < 5 && tipo == "J") {
        message += "<br/>- É necessario anexar os <b>seguintes Documentos:</b><br/><br/>" +
        	        " - Contrato Social e alterações;<br>" +
        	        " - Cartão do CNPJ;<br>" +
        	        " - RG e CPF do(s) sócio(s);<br>" +
        	        " - Comprovante de residência do(s) sócio(s);<br>" +
        	        " - Cópia da procuração (Caso necessário);<br>"+
        			" - Carta Proposta;<br>" +
        			" São necessários <b><u>5</u></b> documentos, você anexou <b><u>"+ hAPI.listAttachments().size() +"</u></b><br>";
    }

    if (message != "") throw "<br/><br/><strong><u>ANEXOS OBRIGATÓRIOS</u></strong><br/>" + message;

    function temAnexo(){
        constraintProcessAttachment = DatasetFactory.createConstraint('processAttachmentPK.processInstanceId', process, process, ConstraintType.MUST);
        datasetProcessAttachment = DatasetFactory.getDataset('processAttachment', null, new Array(constraintProcessAttachment), null);

        for(i = 0; i < datasetProcessAttachment.rowsCount; i++) {
            constraintProcessHistory1 = DatasetFactory.createConstraint('processHistoryPK.movementSequence', datasetProcessAttachment.getValue(i, "originalMovementSequence"), datasetProcessAttachment.getValue(i, "originalMovementSequence"), ConstraintType.MUST);
            constraintProcessHistory2 = DatasetFactory.createConstraint('processHistoryPK.processInstanceId', process, process, ConstraintType.MUST);
            constraintProcessHistory3 = DatasetFactory.createConstraint('processHistoryPK.companyId', datasetProcessAttachment.getValue(i, "processAttachmentPK.companyId"), datasetProcessAttachment.getValue(i, "processAttachmentPK.companyId"), ConstraintType.MUST);
            constraintProcessHistory4 = DatasetFactory.createConstraint('stateSequence', numState, numState, ConstraintType.MUST);
            datasetProcessHistory = DatasetFactory.getDataset('processHistory', null, new Array(constraintProcessHistory1, constraintProcessHistory2, constraintProcessHistory3, constraintProcessHistory4), null);
            for(j = 0; j < datasetProcessHistory.rowsCount; j++) {
                return true;
            }
        }
        return false;
    }

	cardData = hAPI.getCardData(getValue("WKNumProces"));
	codEmpreendimento = cardData.get("codEmpreendimento");
	lote = cardData.get("lote");
	quadra = cardData.get("quadra");
	id = String(codEmpreendimento) + '-' + String(lote) + '-' + String(quadra);

	hAPI.setCardValue("identificador",id);

//	if(numState == 13){
//		hAPI.setCardValue("status","Venda Iniciada");
//	}

	if(numState == 36){
		hAPI.setCardValue("status","Analisando Proposta"); //Em aprovação
	}

	if(numState == 19){
		hAPI.setCardValue("status","Realizar Contraproposta");
	}

	if(numState == 48){
		hAPI.setCardValue("status","Venda Cancelada");
	}

	if(numState == 12){
		hAPI.setCardValue("status","Validando Cadastro");
	}

	if(numState == 9){
		hAPI.setCardValue("status","Cadastro em Correção");
	}

	if(numState == 15){
		hAPI.setCardValue("status","Concluir Venda");
	}

	if(numState == 8){
		hAPI.setCardValue("status","Venda Realizada");
	}
	
}

function integraRMCriarCliFor(cardData){

		loading.setMessage("Realizando integracao...");
		log.info("###integraRMClienteFornecedor");
		var processId = getValue("WKNumProces");

		var COLIGADA = ""+hAPI.getCardValue("codColigada");
		var INTEGRADOR = "admin";
		var SENHA = "Viverde@2020";

		var CONTEXTO = "CODCOLIGADA="+COLIGADA+";CODUSUARIO="+INTEGRADOR;
		var success = false;
		var codigoCFO = "0";
		try{
			var NOME_SERVICO = "WSDATASERVER";
			var CAMINHO_SERVICO = "com.totvs.WsDataServer";
			var SENTENCA = "FinCFODataBR";
			var servico = ServiceManager.getService(NOME_SERVICO);
			var instancia = servico.instantiate(CAMINHO_SERVICO);
			var ws = instancia.getRMIwsDataServer();
			var serviceHelper = servico.getBean();

			//var dsAuth = DatasetFactory.getDataset("dsAutenticacaoTOP",null,null,null);
			var authService = serviceHelper.getBasicAuthenticatedClient(ws, "com.totvs.IwsDataServer", INTEGRADOR, SENHA);

			//var xml = montaXmlRMCriarClienteFornecedor(cardData,codigoCFO);

			//var result = authService.saveRecord(SENTENCA, xml, CONTEXTO);
			//log.info("###RESULT: "+result);

			var c1 = DatasetFactory.createConstraint("CPFCNPJ",cardData.get("cpf"),cardData.get("cpf"),ConstraintType.MUST);
			var dataset = DatasetFactory.getDataset("dsConsultaCliFor",null,[c1],null);
			if(dataset){
				if(dataset.rowsCount > 0){
					codigoCFO = dataset.getValue(0,"CODCFO");
					hAPI.setCardValue("codCfo", codigoCFO);
					log.info("RETORNO SQL CLIENTE EXISTE:::::::::::::::::" + dataset.getValue(0,"CODCFO"));
					var xml = montaXmlRMCriarClienteFornecedor(cardData,codigoCFO);
					
					log.info('-------------------------------------------');
					log.info("XML UPDATE ClienteFornecedor MA: " +  xml);
					log.info('-------------------------------------------');
					
					var result = authService.saveRecord(SENTENCA, xml, CONTEXTO);
					log.info("###RESULT CLIENTE EXISTE - RETORNO: "+result);
					success = true;
				} else {
					hAPI.setCardValue("codCfo", "-1");
					codigoCFO = "-1";
					log.info("INCLUSAO NOVO CLIENTE :::::::::::::::::" + codigoCFO);
					var xml = montaXmlRMCriarClienteFornecedor(cardData,codigoCFO);

					log.info('-------------------------------------------');
					log.info("XML da inclusão: " +  xml);
					log.info('-------------------------------------------');

					var result = authService.saveRecord(SENTENCA, xml, CONTEXTO);
					if(result.substring(0,2) == "0;"){
						log.info("###RESULT NOVO CLIENTE: "+result);
						hAPI.setCardValue("codCfo", result.substring(2));
						success = true;
					} else {
						log.info("###ERRO NO CADASTRO DO CLIENTE FORNECEDOR: "+result);
						throw("Erro na criação do Cliente Fornecedor: "+result);
						success = false;
					}
				}
			} else {
				throw "Erro na criacao do Cliente: "+result;
			}

//			if(!success){
//				throw "Erro na criacao do Cliente: "+result;
//			}

		}catch(e){
			log.info("ERRO INTEGRACAO: "+e);
			throw "ERRO NA INTEGRACAO DO CLIENTE: "+e;
		}

		loading.setMessage("");
		return success;
}

function integraRMCriarVenda(cardData){

	loading.setMessage("Realizando integração...");
	log.info("###integraRMCriarVenda");
	processId = getValue("WKNumProces");

	var INTEGRADOR = "admin";
	var SENHA = "Viverde@2020";

	//venda = cardData.get('venda');

	var CONTEXTO = "CODCOLIGADA="+hAPI.getCardValue('codColigada')+";COD_PESS_EMPR="+hAPI.getCardValue('codEmpreendimento')+";CODUSUARIO="+INTEGRADOR;
	var success = false;
	log.info("CONTEXTO: " + CONTEXTO);

	try{
		var NOME_SERVICO = "WSDATASERVER";
		var CAMINHO_SERVICO = "com.totvs.WsDataServer";
		var SENTENCA = "ImbVendaContratoData";
		var servico = ServiceManager.getService(NOME_SERVICO);
		var instancia = servico.instantiate(CAMINHO_SERVICO);
		var ws = instancia.getRMIwsDataServer();
		var serviceHelper = servico.getBean();

		//dsAuth = DatasetFactory.getDataset("dsAutenticacaoTOP",null,null,null);
		var authService = serviceHelper.getBasicAuthenticatedClient(ws, "com.totvs.IwsDataServer", INTEGRADOR, SENHA);

		var xml2 = montaXmlRMCriarVenda(cardData);

		log.info('-------------------------------------------');
		log.info("XML da inclusão: " +  xml2);
		log.info('-------------------------------------------');
		log.info("vou chamar o saveRecord")
		var result = authService.saveRecord(SENTENCA, xml2, CONTEXTO);

		log.info("###Result RM: "+result);

		var str = ""+result; //"11;123456";
		var n = str.indexOf(";"); // 18;3167
		log.info("Valor do indexOf [n]: " + n);
		if (n == "-1"){
			log.info("vou levantar o erro com: " + str);
			throw str;
		}
		
		var coligada = str.substring(0,n);
		var numVenda = str.substring(n);
		if (numVenda.indexOf(";") >= 0){
			numVenda = numVenda.replace(";", "");
		}

		if( coligada == hAPI.getCardValue('codColigada')){
			var date = new Date();
			var hoje = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss").format(date);
			
			var dataVendaFormatada = "";
			var dataVenda = "" + hAPI.getCardValue("dataVenda");
			if (dataVenda.indexOf("/") > 0){
				dataVenda = dataVenda.split("/");
				dataVendaFormatada = "" + dataVenda[2] + "-" + dataVenda[1] + "-" + dataVenda[0];
			} else {
				dataVendaFormatada = dataVenda;
			}
			
			
			var novoXML = "<ImbVenda>"+
				          "<XCOMPRADOR>"+
						  	"<CODCFO>"+hAPI.getCardValue('codCfo')+"</CODCFO>"+
						    "<CODCOLCFO>0</CODCOLCFO>"+
						    "<PRINCIPAL>1</PRINCIPAL>"+
						    "<PARTICIPACAO>100</PARTICIPACAO>"+
						    //"<DATAENTRADAPLANO>"+hoje+"</DATAENTRADAPLANO>"+
						    "<DATAENTRADAPLANO>"+dataVendaFormatada+"</DATAENTRADAPLANO>"+
						    "<NUM_VENDA>"+numVenda+"</NUM_VENDA>"+
						    "<IDCOMPRADOR>-1</IDCOMPRADOR>"+
						    "<RECCREATEDBY>admin</RECCREATEDBY>"+
						    "<RECCREATEDON>"+hoje+"</RECCREATEDON>"+
						    "<RECMODIFIEDBY>admin</RECMODIFIEDBY>"+
						    "<RECMODIFIEDON>"+hoje+"</RECMODIFIEDON>"+
						    "<CODCOLIGADA>"+hAPI.getCardValue('codColigada')+"</CODCOLIGADA>"+
						  "</XCOMPRADOR>"+
						  "</ImbVenda>";
			log.info("XML do comprador["+getValue("WKNumProces")+"]: " + novoXML);
			var SENTENCA = "ImbVendaCompradorData";
			log.info("Executar a segunda sentença: " + SENTENCA);
			var result = ""+authService.saveRecord(SENTENCA, novoXML, CONTEXTO);
			log.info("retorno do ["+SENTENCA+"]: " + result);
			if (result.indexOf(";") < 0){
				throw result;
			}
			
			return true;
		} else {
			throw "Erro na criacao da Venda: "+result;
		}

	}catch(e){
		log.info("ERRO INTEGRACAO: "+e);
		throw "ERRO NA INTEGRACAO DA VENDA: "+e;
	}

	loading.setMessage("");
	return success;

}

function beforeStateEntry(sequenceId){

//	if (sequenceId == 12) {
//		var dat = new Date();
//		var ano = dat.getFullYear();
//		var dia = dat.getDate();
//		var mes = dat.getMonth() + 1;
//
//		parseInt(mes);
//		parseInt(dia);
//
//		if (mes <= 9) {
//			mes = "0" + mes;
//		}
//		if (dia <= 9) {
//			dia = "0" + dia;
//		}
//
//		var dataVenda = dia + "/" + mes + "/" + ano;
//		hAPI.setCardValue("dataVenda", dataVenda);
//	}
	
	if(sequenceId == 8){
		log.info("@@@@@@@@@@@ CADASTRANDO VENDA");
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		integraRMCriarVenda(cardData);
	}
	
	if(sequenceId == 15){
		log.info("@@@@@@@@@@@ CADASTRANDO CLIENTE FORNECEDOR");
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		integraRMCriarCliFor(cardData);
	}
	
	// ********************************************************
	// ******************* ENVIO DOS EMAILS *******************
	// ********************************************************
	if (sequenceId == 36){ // Analisar proposta
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Diretoria");
	} else if (sequenceId == 19){ // Realizar contra proposta
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Comercial - Administrativo");
	} else if (sequenceId == 9){ // Corrigir cadastro
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Comercial - Administrativo");
	} else if (sequenceId == 12){ // Validar Dados do Cadastro
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Suprimentos");
	} else if (sequenceId == 15){ // Concluir venda
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Docusign");
	} else if (sequenceId == 8){ // Final
		var cardData = hAPI.getCardData(getValue("WKNumProces"));
		enviaEmail(cardData, "Suprimentos");
	}
	
	
	/*
	13 - Inicio
	36 - Analista Proposta
	17 - Exclusive
	19 - Relizar Contraproposta
	48 - End Cancel
	12 - Validar Dados do Cadastro
	40 - Exclusive
	9  - Corrigir Cadastro
	15 - Concluir Venda
	8 - End
	*/

//	if(sequenceId == 13){
//		hAPI.setCardValue("status","Venda Iniciada");
//	}

	if(sequenceId == 36){		
		hAPI.setCardValue("status","Analisando Proposta"); //Em aprovação
	}

	if(sequenceId == 19){
		hAPI.setCardValue("status","Realizar Contraproposta");
	}

	if(sequenceId == 48){
		hAPI.setCardValue("status","Venda Cancelada");
	}

	if(sequenceId == 12){
		hAPI.setCardValue("status","Validando Cadastro");
	}

	if(sequenceId == 9){
		hAPI.setCardValue("status","Cadastro em Correção");
	}

	if(sequenceId == 15){
		hAPI.setCardValue("status","Concluir Venda");
	}

	if(sequenceId == 8){
		hAPI.setCardValue("status","Venda Realizada");
	}
}

function enviaEmail(cardData, grupo){
	try{
	    //Monta mapa com parâmetros do template - esses parâmetros são recebidos no template do e-mail
	    var parametros = new java.util.HashMap();
	    
	    parametros.put("SOLICITACAO", String(getValue("WKNumProces")));
	    parametros.put("SOLICITANTE", cardData.get("solicitante"));
	    parametros.put("CODEMPREENDIMENTO", cardData.get("codEmpreendimento"));
	    parametros.put("EMPREENDIMENTO", cardData.get("empreendimento"));
	    parametros.put("CORRETOR", cardData.get("nomeCorretor"));
	    parametros.put("RENDA", cardData.get("rendacliente"));
	    parametros.put("LOTE", cardData.get("lote"));
	    parametros.put("QUADRA", cardData.get("quadra"));
	    parametros.put("CPF", cardData.get("cpf"));
	    parametros.put("NOMECLIENTE", cardData.get("nomecliente"));
	    parametros.put("URL", cardData.get("url"));

	    //Este parâmetro é obrigatório e representa o assunto do e-mail
	    parametros.put("subject", cardData.get("empreendimento") + " Q" + cardData.get("quadra") + "L" + cardData.get("lote"));
	    
	    var GRUPO = grupo;
	    
		var c1 = DatasetFactory.createConstraint("GRUPO", GRUPO, GRUPO, ConstraintType.MUST);
		var constraints = new Array(c1);
		var dataset = DatasetFactory.getDataset("dsEmailGrupo", null, constraints, null);
				
		if ( dataset.rowsCount > 0 ){
		    var indexes = dataset.rowsCount;
		    for (var i = 0; i <= indexes; i++) {
				if ( dataset.getValue(i,"EMAIL") != "" && dataset.getValue(i,"EMAIL") != null && dataset.getValue(i,"EMAIL") != undefined)	{
					//Monta lista de destinatários
		            var destinatarios = new java.util.ArrayList();
		            var email = dataset.getValue(i,"EMAIL");
		            destinatarios.add(email); 
		          //Envia e-mail
					var remetente = hAPI.getCardValue("admin");
				    notifier.notify(getValue("WKUser"), "tpl_SolicitacaoVendaMA", parametros, destinatarios, "text/html");
				}
		    }
		}
	} catch(e){
	    log.info(e);
	}
}

function formatarData(dt) {
	  if (dt != "" && dt != null && dt != undefined){
		  var ano = dt.substring(0, 4);
		  var mes = dt.substring(5, 7);
		  var dia = dt.substring(8, 10);
		  var data = dia + "/" + mes + "/" + ano;
		  return data;
	  }
}

